'use client';

import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Typography,
  Button,
  Stack,
  Box,
  Card,
  TextField,
  MenuItem,
} from '@mui/material';
import React, { useState } from 'react';

interface VariantOption {
  name: string;
  width: number;
  height: number;
  price: number;
}

interface FancyVariantModalProps {
  open: boolean;
  onClose: () => void;
  onSelect: (option: VariantOption, quantity: number, name: string) => void;
  productName: string;
}

const variantList: VariantOption[] = [
  { name: 'Portrait', width: 55, height: 90, price: 3 },
  { name: 'Landscape', width: 90, height: 55, price: 3 },
];

export default function FancyVariantModal({
  open,
  onClose,
  onSelect,
  productName,
}: FancyVariantModalProps) {
  const [selected, setSelected] = useState<VariantOption | null>(null);

  const [sides, setSides] = useState<'1' | '2'>('1');
  const [material, setMaterial] = useState('กระดาษ 260 แกรม');
  const [quantity, setQuantity] = useState(100);

  return (
    <Dialog open={open} onClose={onClose} fullWidth maxWidth="md">
      <DialogTitle>{productName}</DialogTitle>
      <DialogContent dividers>
        <Box sx={{ display: 'flex', gap: 2, justifyContent: 'center' }}>
          {variantList.map((v, i) => {
            const isSelected = selected?.name === v.name;
            return (
              <Card
                key={i}
                onClick={() => setSelected(v)}
                sx={{
                  width: 160,
                  height: 200,
                  border: isSelected
                    ? '2px solid #1976d2'
                    : '1px solid #ddd',
                  borderRadius: 2,
                  p: 4,
                  cursor: 'pointer',
                  position: 'relative',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'space-between',
                  '&:hover': {
                    boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
                  },
                }}
              >
                {/* ราคา มุมบนซ้าย */}
                <Box
                  sx={{
                    position: 'absolute',
                    top: 8,
                    left: 8,
                    bgcolor: 'white',
                    px: 0.5,
                    py: 0.2,
                    borderRadius: 1,
                    fontSize: 12,
                    fontWeight: 'bold',
                    border: '1px solid #ccc',
                  }}
                >
                  ฿ {v.price.toFixed(2)}
                </Box>

                {/* กล่อง preview */}
                <Box
                  sx={{
                    flex: 1,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    width: '100%',
                  }}
                >
                  <Box
                    sx={{
                      width: v.width > v.height ? '80%' : '50%',
                      height: v.height > v.width ? '80%' : '50%',
                      border: '2px solid #333',
                    }}
                  />
                </Box>

                {/* ข้อความด้านล่าง */}
                <Box sx={{ textAlign: 'center', mt: 1 }}>
                  <Typography variant="body2" fontWeight={600}>
                    {v.width} × {v.height} mm
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    ราคาเริ่มต้น
                  </Typography>
                </Box>
              </Card>
            );
          })}
        </Box>
      </DialogContent>
      <Stack direction={{ xs: 'column', sm: 'row' }} spacing={2} sx={{ mt: 2 }}>
  {/* เลือกด้าน */}
  <TextField
    select
    label="การพิมพ์"
    value={sides}
    onChange={(e) => setSides(e.target.value as '1' | '2')}
    fullWidth
  >
    <MenuItem value="1">1 ด้าน</MenuItem>
    <MenuItem value="2">2 ด้าน</MenuItem>
  </TextField>

  {/* เลือกวัสดุ */}
  <TextField
    select
    label="วัสดุกระดาษ"
    value={material}
    onChange={(e) => setMaterial(e.target.value)}
    fullWidth
  >
    <MenuItem value="กระดาษ 260 แกรม">กระดาษ 260 แกรม</MenuItem>
    <MenuItem value="กระดาษ 300 แกรม">กระดาษ 300 แกรม</MenuItem>
    <MenuItem value="กระดาษพรีเมียม">กระดาษพรีเมียม</MenuItem>
  </TextField>
</Stack>
      <DialogActions>
        <Button onClick={onClose}>ยกเลิก</Button>
        <Button
          variant="contained"
          disabled={!selected}
          onClick={() =>
            selected && onSelect(selected, 100, selected.name) // default qty=100
          }
        >
          ถัดไป
        </Button>
      </DialogActions>
    </Dialog>
  );
}
